const BRANCH = 32;

type Leaf<T> = { type: 'leaf'; values: T[] };
type Internal<T> = { type: 'internal'; children: (Leaf<T> | Internal<T>)[] };
type Node<T> = Leaf<T> | Internal<T>;

export class PersistentVector<T> {
  private constructor(
    private readonly root: Node<T>,
    private readonly _size: number
  ) {}

  static empty<T>(): PersistentVector<T> {
    return new PersistentVector<T>({ type: 'leaf', values: [] }, 0);
  }

  get size(): number {
    return this._size;
  }

  get(i: number): T {
    if (i < 0 || i >= this._size) {
      throw new RangeError(`Index ${i} out of range [0, ${this._size})`);
    }
    let node: Node<T> = this.root;
    let idx = i;
    let depth = 0;
    let s = this._size;
    while (s > 0) {
      s = Math.ceil(s / BRANCH);
      depth++;
    }
    for (let d = depth; d > 0; d--) {
      const divisor = BRANCH ** (d - 1);
      const childIdx = Math.floor(idx / divisor);
      idx %= divisor;
      node = (node as Internal<T>).children[childIdx];
    }
    return (node as Leaf<T>).values[idx];
  }

  push(value: T): PersistentVector<T> {
    const newSize = this._size + 1;
    let depth = 0;
    let s = newSize;
    while (s > 0) {
      s = Math.ceil(s / BRANCH);
      depth++;
    }
    const initialDivisor = BRANCH ** (depth - 1);
    const newRoot = this.pushToNode(this.root, this._size, initialDivisor, value);
    return new PersistentVector(newRoot, newSize);
  }

  private pushToNode(node: Node<T>, index: number, divisor: number, value: T): Node<T> {
    if (divisor === 1) {
      const newValues = [...node.values, value];
      if (newValues.length > BRANCH) {
        const left: Leaf<T> = { type: 'leaf', values: node.values };
        const right: Leaf<T> = { type: 'leaf', values: [value] };
        return { type: 'internal', children: [left, right] } as Internal<T>;
      }
      return { type: 'leaf', values: newValues };
    }
    const childIdx = Math.floor(index / divisor);
    const nextDivisor = divisor / BRANCH;
    const newChildren: (Leaf<T> | Internal<T>)[] = [...(node as Internal<T>).children];
    if (childIdx < newChildren.length) {
      newChildren[childIdx] = this.pushToNode(newChildren[childIdx], index, nextDivisor, value);
    } else {
      newChildren.push({ type: 'leaf', values: [value] });
    }
    if (newChildren.length > BRANCH) {
      const leftChildren = newChildren.slice(0, BRANCH);
      const rightChildren = newChildren.slice(BRANCH);
      const left: Internal<T> = { type: 'internal', children: leftChildren };
      const right: Internal<T> = { type: 'internal', children: rightChildren };
      return { type: 'internal', children: [left, right] } as Internal<T>;
    }
    return { type: 'internal', children: newChildren };
  }
}

