export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private handlers = new Map<string, Array<(...args: unknown[]) => void>>();

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const list = this.handlers.get(name) ?? [];
    list.push(handler as (...args: unknown[]) => void);
    this.handlers.set(name, list);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this.handlers.get(name);
    if (handlers) {
      for (const handler of handlers) {
        handler(...args);
      }
    }
  }
}

class NumberHeap {
  private data: number[] = [];
  private isMin: boolean;

  constructor(isMin: boolean) {
    this.isMin = isMin;
  }

  push(val: number): void {
    this.data.push(val);
    this.bubbleUp(this.data.length - 1);
  }

  pop(): number {
    if (this.data.length === 0) throw new Error("Heap empty");
    const top = this.data[0];
    this.data[0] = this.data.pop()!;
    if (this.data.length > 0) this.bubbleDown(0);
    return top;
  }

  peek(): number {
    if (this.data.length === 0) throw new Error("Heap empty");
    return this.data[0];
  }

  get size(): number {
    return this.data.length;
  }

  private bubbleUp(idx: number): void {
    while (idx > 0) {
      const parent = (idx - 1) >> 1;
      const shouldSwap = this.isMin
        ? this.data[idx] < this.data[parent]
        : this.data[idx] > this.data[parent];
      if (shouldSwap) {
        [this.data[idx], this.data[parent]] = [this.data[parent], this.data[idx]];
        idx = parent;
      } else {
        break;
      }
    }
  }

  private bubbleDown(idx: number): void {
    const n = this.data.length;
    while (true) {
      let target = idx;
      const left = 2 * idx + 1;
      const right = 2 * idx + 2;
      if (left < n) {
        const shouldSwapLeft = this.isMin
          ? this.data[left] < this.data[target]
          : this.data[left] > this.data[target];
        if (shouldSwapLeft) target = left;
      }
      if (right < n) {
        const shouldSwapRight = this.isMin
          ? this.data[right] < this.data[target]
          : this.data[right] > this.data[target];
        if (shouldSwapRight) target = right;
      }
      if (target !== idx) {
        [this.data[idx], this.data[target]] = [this.data[target], this.data[idx]];
        idx = target;
      } else {
        break;
      }
    }
  }
}

export class MedianStream {
  private left: NumberHeap;
  private right: NumberHeap;

  constructor() {
    this.left = new NumberHeap(false);
    this.right = new NumberHeap(true);
  }

  add(n: number): void {
    this.left.push(n);
    this.right.push(this.left.pop());
    if (this.right.size > this.left.size) {
      this.left.push(this.right.pop());
    }
  }

  median(): number {
    if (this.left.size === 0) {
      throw new Error("No elements added");
    }
    if (this.left.size > this.right.size) {
      return this.left.peek();
    }
    return (this.left.peek() + this.right.peek()) / 2;
  }
}
